// ================================================================
// register.component.ts — Componente de Registro de Nuevos Usuarios
// ================================================================
// Muy parecido al LoginComponent, pero con un campo más (Nombre)
// y una validación extra: confirmar que las contraseñas coincidan.
//
// FLUJO DEL REGISTRO:
// 1. Usuario llena nombre, email, contraseña y confirmación
// 2. Angular valida el formulario en tiempo real (frontend)
// 3. Al submit, llamamos a AuthService.register()
// 4. El backend crea el usuario en PostgreSQL con BCrypt Hash
// 5. El backend devuelve 200 OK con mensaje de éxito
// 6. Mostramos el mensaje y redirigimos al login después de 2 segundos
// ================================================================
import { Component } from '@angular/core';
import { FormBuilder, FormGroup, Validators, AbstractControl } from '@angular/forms';
import { Router } from '@angular/router';
import { AuthService } from '../../../services/auth.service';

// ================================================================
// FUNCIÓN VALIDADOR PERSONALIZADO: passwordsMatch
// ================================================================
// Angular permite crear validadores personalizados para reglas de negocio
// que no existen en la lista de Validators de Angular.
// Esta función verifica que "password" y "confirmPassword" sean iguales.
// Retorna null si son iguales (sin error), o un objeto de error si difieren.
function passwordsMatch(control: AbstractControl) {
  // AbstractControl nos da acceso al FormGroup completo
  const password = control.get('password')?.value; // Leemos el valor de "password"
  const confirm = control.get('confirmPassword')?.value; // Leemos el valor de "confirmPassword"

  // Si los valores son iguales, no hay error → retornamos null
  if (password === confirm) return null;

  // Si son distintos, retornamos un objeto de error.
  // El nombre del error ('passwordsMismatch') lo usamos en el HTML para mostrarlo.
  return { passwordsMismatch: true };
}

@Component({
  selector: 'app-register',
  templateUrl: './register.component.html',
  styleUrls: ['./register.component.css']
})
export class RegisterComponent {

  // PROPIEDADES DEL COMPONENTE
  registerForm: FormGroup;
  isLoading: boolean = false;
  errorMessage: string = '';
  successMessage: string = ''; // Mensaje de éxito al registrar
  showPassword: boolean = false;
  showConfirmPassword: boolean = false;

  constructor(
    private fb: FormBuilder,
    private authService: AuthService,
    private router: Router
  ) {
    // ============================================================
    // DEFINICIÓN DEL FORMULARIO DE REGISTRO
    // ============================================================
    // El segundo argumento de fb.group() acepta validadores a nivel de grupo.
    // passwordsMatch se ejecuta sobre el grupo completo para comparar dos campos.
    this.registerForm = this.fb.group({

      // Campo Nombre: mínimo 3 caracteres para evitar nombres muy cortos
      nombre: ['', [Validators.required, Validators.minLength(3)]],

      // Campo Email: formato válido obligatorio
      email: ['', [Validators.required, Validators.email]],

      // Campo Contraseña: mínimo 6 caracteres (igual que el backend lo exige)
      password: ['', [Validators.required, Validators.minLength(6)]],

      // Campo Confirmar Contraseña: solo required en el control individual
      // La validación de coincidencia la hace el validador del GRUPO
      confirmPassword: ['', Validators.required]

    // El segundo argumento es la configuración del FormGroup.
    // validators: [passwordsMatch] aplica nuestra función al grupo completo.
    }, { validators: passwordsMatch });
  }

  // Getter para acceso rápido a los controles desde el HTML
  get f() {
    return this.registerForm.controls;
  }

  togglePassword() {
    this.showPassword = !this.showPassword;
  }

  toggleConfirmPassword() {
    this.showConfirmPassword = !this.showConfirmPassword;
  }

  // ============================================================
  // MÉTODO PRINCIPAL: onSubmit()
  // ============================================================
  onSubmit() {
    // Verificamos que el formulario sea válido (incluye la validación del grupo passwordsMatch)
    if (this.registerForm.invalid) return;

    // Limpiamos mensajes previos
    this.errorMessage = '';
    this.successMessage = '';
    this.isLoading = true;

    // Preparamos el objeto con solo los datos que el backend necesita.
    // NO enviamos "confirmPassword" porque el backend no lo espera.
    const registerData = {
      nombre: this.f['nombre'].value,
      email: this.f['email'].value,
      password: this.f['password'].value
    };

    // Llamamos al servicio de registro
    this.authService.register(registerData).subscribe({
      next: (response: any) => {
        // ✅ REGISTRO EXITOSO
        this.isLoading = false;
        this.successMessage = '¡Cuenta creada exitosamente! Redirigiendo al login...';
        // Redirigimos al login automáticamente después de 2 segundos
        // setTimeout es una función de JavaScript que ejecuta algo después de X milisegundos
        setTimeout(() => {
          this.router.navigate(['/login']);
        }, 2000); // 2000ms = 2 segundos
      },
      error: (err) => {
        // ❌ ERROR EN EL REGISTRO (email ya en uso, error de servidor, etc.)
        this.isLoading = false;
        this.errorMessage = err.error?.mensaje || 'Error al crear la cuenta. Intenta de nuevo.';
      }
    });
  }
}
<!-- ================================================================
     register.component.html — Formulario de Registro
     ================================================================ -->

<div class="auth-page">
  <div class="auth-card fade-in-up">

    <!-- ENCABEZADO -->
    <div class="auth-header">
      <div class="auth-icon-wrapper">
        <i class="bi bi-person-plus-fill"></i>
      </div>
      <h1 class="auth-title">Crear Cuenta</h1>
      <p class="auth-subtitle">Únete y reserva tu cancha favorita</p>
    </div>

    <!-- ALERTA DE ÉXITO — aparece cuando el registro fue exitoso -->
    <!-- *ngIf hace que este div sea invisible hasta que successMessage tenga valor -->
    <div class="alert alert-success" *ngIf="successMessage" role="alert" id="register-success-alert">
      <i class="bi bi-check-circle-fill me-2"></i>
      {{ successMessage }}
    </div>

    <!-- ALERTA DE ERROR — aparece cuando el registro falla -->
    <div class="alert alert-danger" *ngIf="errorMessage" role="alert" id="register-error-alert">
      <i class="bi bi-exclamation-triangle-fill me-2"></i>
      {{ errorMessage }}
    </div>

    <!-- ============================================================
         FORMULARIO REACTIVO DE REGISTRO
         ============================================================ -->
    <form [formGroup]="registerForm" (ngSubmit)="onSubmit()">

      <!-- ==================== CAMPO NOMBRE ==================== -->
      <div class="mb-3">
        <label for="reg-nombre" class="form-label">
          <i class="bi bi-person me-2"></i>Nombre Completo
        </label>
        <input type="text"
               class="form-control"
               id="reg-nombre"
               formControlName="nombre"
               [class.is-invalid]="f['nombre'].invalid && f['nombre'].touched"
               [class.is-valid]="f['nombre'].valid && f['nombre'].touched"
               placeholder="Carlos Rodríguez"
               autocomplete="name">

        <!-- Mensajes de validación del nombre -->
        <div class="invalid-feedback" *ngIf="f['nombre'].touched && f['nombre'].errors">
          <span *ngIf="f['nombre'].errors?.['required']">
            <i class="bi bi-exclamation-circle me-1"></i>El nombre es obligatorio
          </span>
          <span *ngIf="f['nombre'].errors?.['minlength']">
            <i class="bi bi-exclamation-circle me-1"></i>El nombre debe tener al menos 3 caracteres
          </span>
        </div>
        <!-- El ✓ verde aparece cuando el campo es válido y fue tocado -->
        <div class="valid-feedback">
          <i class="bi bi-check-circle me-1"></i>¡Nombre válido!
        </div>
      </div>

      <!-- ==================== CAMPO EMAIL ==================== -->
      <div class="mb-3">
        <label for="reg-email" class="form-label">
          <i class="bi bi-envelope me-2"></i>Correo Electrónico
        </label>
        <input type="email"
               class="form-control"
               id="reg-email"
               formControlName="email"
               [class.is-invalid]="f['email'].invalid && f['email'].touched"
               [class.is-valid]="f['email'].valid && f['email'].touched"
               placeholder="miusuario@correo.com"
               autocomplete="email">

        <div class="invalid-feedback" *ngIf="f['email'].touched && f['email'].errors">
          <span *ngIf="f['email'].errors?.['required']">
            <i class="bi bi-exclamation-circle me-1"></i>El email es obligatorio
          </span>
          <span *ngIf="f['email'].errors?.['email']">
            <i class="bi bi-exclamation-circle me-1"></i>Escribe un email válido
          </span>
        </div>
        <div class="valid-feedback">
          <i class="bi bi-check-circle me-1"></i>Email válido
        </div>
      </div>

      <!-- ==================== CAMPO CONTRASEÑA ==================== -->
      <div class="mb-3">
        <label for="reg-password" class="form-label">
          <i class="bi bi-lock me-2"></i>Contraseña
        </label>
        <div class="input-password-wrapper">
          <input [type]="showPassword ? 'text' : 'password'"
                 class="form-control"
                 id="reg-password"
                 formControlName="password"
                 [class.is-invalid]="f['password'].invalid && f['password'].touched"
                 [class.is-valid]="f['password'].valid && f['password'].touched"
                 placeholder="Mínimo 6 caracteres"
                 autocomplete="new-password">
          <button type="button" class="password-toggle" (click)="togglePassword()" id="btn-toggle-reg-password">
            <i class="bi" [class.bi-eye]="!showPassword" [class.bi-eye-slash]="showPassword"></i>
          </button>
        </div>
        <div class="invalid-feedback" *ngIf="f['password'].touched && f['password'].errors">
          <span *ngIf="f['password'].errors?.['required']">
            <i class="bi bi-exclamation-circle me-1"></i>La contraseña es obligatoria
          </span>
          <span *ngIf="f['password'].errors?.['minlength']">
            <i class="bi bi-exclamation-circle me-1"></i>Debe tener al menos 6 caracteres
          </span>
        </div>
        <div class="valid-feedback">
          <i class="bi bi-check-circle me-1"></i>Contraseña válida
        </div>
      </div>

      <!-- ==================== CAMPO CONFIRMAR CONTRASEÑA ==================== -->
      <div class="mb-4">
        <label for="reg-confirm" class="form-label">
          <i class="bi bi-shield-lock me-2"></i>Confirmar Contraseña
        </label>
        <div class="input-password-wrapper">
          <input [type]="showConfirmPassword ? 'text' : 'password'"
                 class="form-control"
                 id="reg-confirm"
                 formControlName="confirmPassword"
                 [class.is-invalid]="(f['confirmPassword'].touched && f['confirmPassword'].errors) ||
                                     (f['confirmPassword'].touched && registerForm.errors?.['passwordsMismatch'])"
                 [class.is-valid]="f['confirmPassword'].valid && f['confirmPassword'].touched && !registerForm.errors?.['passwordsMismatch']"
                 placeholder="Repite tu contraseña"
                 autocomplete="new-password">
          <button type="button" class="password-toggle" (click)="toggleConfirmPassword()" id="btn-toggle-reg-confirm">
            <i class="bi" [class.bi-eye]="!showConfirmPassword" [class.bi-eye-slash]="showConfirmPassword"></i>
          </button>
        </div>

        <!-- Error del campo individual (vacío) -->
        <div class="invalid-feedback" *ngIf="f['confirmPassword'].touched && f['confirmPassword'].errors">
          <span *ngIf="f['confirmPassword'].errors?.['required']">
            <i class="bi bi-exclamation-circle me-1"></i>Confirma tu contraseña
          </span>
        </div>

        <!-- Error del GRUPO: las contraseñas no coinciden.
             registerForm.errors accede a los errores del validador del grupo (passwordsMatch) -->
        <div class="invalid-feedback"
             *ngIf="f['confirmPassword'].touched && registerForm.errors?.['passwordsMismatch']">
          <i class="bi bi-exclamation-circle me-1"></i>Las contraseñas no coinciden
        </div>

        <div class="valid-feedback"
             *ngIf="f['confirmPassword'].valid && !registerForm.errors?.['passwordsMismatch'] && f['confirmPassword'].touched">
          <i class="bi bi-check-circle me-1"></i>Las contraseñas coinciden
        </div>
      </div>

      <!-- BOTÓN DE SUBMIT -->
      <button type="submit"
              class="btn btn-success w-100 btn-auth-submit"
              [disabled]="registerForm.invalid || isLoading"
              id="btn-register-submit">
        <span *ngIf="isLoading" class="spinner-border spinner-border-sm me-2" role="status"></span>
        <i class="bi bi-person-check me-2" *ngIf="!isLoading"></i>
        {{ isLoading ? 'Creando cuenta...' : 'Crear Cuenta' }}
      </button>

    </form>

    <!-- PIE: Enlace al login -->
    <div class="auth-footer">
      <p class="mb-0">
        ¿Ya tienes cuenta?
        <a [routerLink]="['/login']" class="auth-link" id="link-ir-login">
          Inicia sesión aquí
        </a>
      </p>
    </div>

  </div><!-- fin auth-card -->
</div><!-- fin auth-page -->
